// Helper: Get vocab by ID
export const getVocab = (id) => {
  const item = VOCAB_DB[id];
  if (!item) {
    console.warn(`⚠️ Vocab '${id}' not found`);
    return null;
  }
  console.log(`✅ Found: ${item.word}`);
  return item;
};

// Helper: Convert to teach step format
export const toTeach = (v) => v ? {
  type:"teach",
  nl:v.word,
  en:v.translation,
  phonetic:v.phonetic,
  img:v.img||"📝",
  example:v.examples?.[0]?.nl||"",
  exampleEn:v.examples?.[0]?.en||"",
  note:v.note||`${v.type}`
} : null;

