// ── CEFR LEVEL SYSTEM ──
export const CEFR_LEVELS = [
  {id:"A1.1",band:"A1",label:"Beginner",color:"#2ECDA7",desc:"First words and fixed phrases"},
  {id:"A1.2",band:"A1",label:"Beginner",color:"#2ECDA7",desc:"Simple transactional language"},
  {id:"A2.1",band:"A2",label:"Elementary",color:"#4A8FE7",desc:"Daily situations and routines"},
  {id:"A2.2",band:"A2",label:"Elementary",color:"#4A8FE7",desc:"Past, future, comparisons"},
  {id:"B1.1",band:"B1",label:"Intermediate",color:"var(--purple-accent-text)",desc:"Abstract topics and formal register"},
  {id:"B1.2",band:"B1",label:"Intermediate",color:"var(--purple-accent-text)",desc:"Idioms and cultural fluency"},
  {id:"B2.1",band:"B2",label:"Upper-Intermediate",color:"#E8475E",desc:"Complex argument and nuance"},
  {id:"B2.2",band:"B2",label:"Upper-Intermediate",color:"#E8475E",desc:"Professional and academic register"},
];
export const getCefrInfo=(levelId)=>CEFR_LEVELS.find(l=>l.id===levelId)||CEFR_LEVELS.find(l=>l.band===levelId)||(levelId&&CEFR_LEVELS.find(l=>levelId.startsWith(l.band+'.')))||CEFR_LEVELS[0];
export const getCefrBandColor=(band)=>({A1:"#2ECDA7",A2:"#4A8FE7",B1:"#7B5EE8",B2:"#E8475E",C1:"#F5A623",C2:"#E74A8F"}[band]||"#888");

