// ── FK SCHEMA DOCUMENTATION ──
// Every language in FOUNDATIONS_BY_LANG should follow this structural pattern:
//   1. writing_system_overview — Script type, direction, key concepts
//   2. alphabet_grid — 2D grid of ALL letters/characters (REQUIRED, even for Latin)
//   3. pronunciation/phonics — Sounds that differ from English/base language
//   4. orthography_rules — Spelling rules, syllable structure, consonant/vowel patterns
//   5. practice_sets — Placeholder for future interactive drills (reuse mc/match/typing steps)
//
// Grid format: {cols:N, headers:[...], rows:[{label,color,cells:[{ch,rom},...]}]}
// Every alphabet MUST render as a 2D grid — no exceptions.
// FK progress is tracked via user.progress.lessons[`${lang}:foundation:${secId}:${itemIdx}`]
// To add a new language: fill in sections following the schema above. The renderer is universal.

// ── FOUNDATION_SCHEMA: defines required modules per writing system type ──
export const FOUNDATION_SCHEMA = {
  latin: {
    required: ["alphabet_grid","pronunciation","orthography"],
    optional: ["digraphs","vowel_system","stress_patterns","spelling_rules"],
    desc: "For languages using Latin script (Dutch, German, French, etc.)"
  },
  arabic: {
    required: ["alphabet_grid","letter_forms","non_connectors","diacritics"],
    optional: ["dot_families","shadda_tanwin","reading_drills"],
    desc: "For Arabic script — positional forms are essential for literacy"
  },
  cjk: {
    required: ["writing_overview","character_grid"],
    optional: ["tones","radicals","stroke_order"],
    desc: "For Chinese/Japanese/Korean — syllabaries or logographic systems"
  },
  syllabary: {
    required: ["character_grid","reading_order"],
    optional: ["voiced_marks","combination_rules"],
    desc: "For syllabary systems (Japanese kana, Korean jamo)"
  }
};
// Schema→language mapping for validation
export const FK_SCHEMA_MAP = {nl:"latin",de:"latin",fr:"latin",es:"latin",ro:"latin",en:"latin",ar:"arabic",ja:"syllabary",ko:"syllabary",zh:"cjk",ru:"latin"};

// ── FK PEDAGOGY ENGINE (Batch 5) ──
// Upgrades FK from pure reference → learnable curriculum.
// FK items can now have a `moduleType` field that determines rendering + interaction.
// If no moduleType is set, item renders as "info" (backwards compatible).
//
// FK item schema (extended):
//   {
//     fk: "fk_key",           // FK registry key
//     title: "...",            // display title
//     desc: "...",             // description text
//     moduleType: "info",      // one of FK_MODULE_TYPES (default: "info")
//     grid: {...},             // optional: 2D grid data
//     examples: [...],         // optional: example strings
//     practice: {...},         // optional: practice block (see FK_PRACTICE_TYPES)
//   }
//
// Practice block schema:
//   {
//     type: "mc"|"match"|"identify"|"trace",
//     items: [...],            // practice items (format depends on type)
//   }
//
// Source-language note: All desc/title strings are currently in English.
// Future source-language swapping will route these through MKG keys.
// When adding new FK items, prefer MKG-backed strings where possible.

// Valid module types for FK items
export const FK_MODULE_TYPES = {
  info:        {label:"Information",desc:"Read-only reference material (default)",icon:"📖",interactive:false},
  grid:        {label:"Character Grid",desc:"Interactive 2D character/letter grid",icon:"🔤",interactive:true},
  recognition: {label:"Recognition",desc:"Identify characters, sounds, or patterns",icon:"👁️",interactive:true},
  writing:     {label:"Writing",desc:"Trace or copy characters (future: canvas input)",icon:"✍️",interactive:true},
  production:  {label:"Production",desc:"Produce characters or words from prompts",icon:"🎯",interactive:true},
  contrast:    {label:"Contrast",desc:"Distinguish similar-looking or similar-sounding items",icon:"⚖️",interactive:true},
};

// Valid practice block types (embedded in FK items with moduleType != "info")
export const FK_PRACTICE_TYPES = {
  mc:       {label:"Multiple Choice",desc:"Select the correct answer from options"},
  match:    {label:"Match Pairs",desc:"Match items from two columns"},
  identify: {label:"Identify",desc:"Tap the correct item from a set"},
  trace:    {label:"Trace/Copy",desc:"Write or trace a character (future: handwriting input)"},
};

// ── FK Learning Flow (per script type) ──
// Defines the recommended pedagogical progression for each writing system.
// recognition → production is the universal flow.
export const FK_LEARNING_FLOWS = {
  latin:    ["info","grid","recognition","contrast","production"],
  arabic:   ["info","grid","recognition","contrast","writing","production"],
  cyrillic: ["info","grid","recognition","contrast","writing","production"],
  hangul:   ["info","grid","recognition","writing","production"],
  kana:     ["info","grid","recognition","writing","production"],
  hanzi:    ["info","grid","recognition","writing","production"],
  cjk:      ["info","grid","recognition","writing","production"],
};

