// ── MKG: Meaning Key Glossary — pedagogy layer (Pipeline Step 5) ──
// Extends MK with explanations, grammar notes, culture notes, hints.
// p(key, baseLang) resolves a pedagogy string. Returns "" if not found (graceful).
export const MKG = {
  // Unit template titles
  mkg_u1_title: {en:"Greetings & Basics",ar:"التحيات والأساسيات",fr:"Salutations et bases",es:"Saludos y básicos"},
  mkg_u2_title: {en:"Numbers & Time",ar:"الأرقام والوقت",fr:"Nombres et heure",es:"Números y hora"},
  mkg_u3_title: {en:"Food & Drink",ar:"الطعام والشراب",fr:"Nourriture et boisson",es:"Comida y bebida"},
  mkg_u4_title: {en:"Getting Around",ar:"التنقل",fr:"Se déplacer",es:"Moverse"},
  mkg_u5_title: {en:"Daily Life",ar:"الحياة اليومية",fr:"Vie quotidienne",es:"Vida diaria"},
  // Grammar hints (expandable per language)
  mkg_nl_vowel_rule: {en:"Dutch vowels: open syllable = long vowel, closed syllable = short vowel. Double the vowel letter (aa/ee/oo/uu) to force long in closed syllables."},
  mkg_nl_consonant_rule: {en:"Consonant doubling: short vowel + single consonant → double that consonant before -en/-ing/-er (e.g., lak → lakken)."},
  mkg_de_formal: {en:"Use 'Sie' (capitalized) for formal address. 'Du' for friends/family/children."},
  mkg_ar_rtl: {en:"Arabic reads right-to-left. Numbers still read left-to-right."},
  // TODO: Expand as languages are built
};
export function p(key, baseLang="en") {
  const entry = MKG[key];
  if (!entry) return "";
  return entry[baseLang] || entry.en || "";
}

/*
RULE: Every language in LANGUAGES must have an FK_PLAYTHROUGH entry
(even if it's just a placeholder with stages:[]).
This is enforced by DEV GUARD below.

SCRIPT_BLUEPRINTS defines the logical stage order per writing system.
FK_PLAYTHROUGH contains the actual lesson content.
Lessons reuse the same step shapes as the main LessonEngine:
  {type:"teach",kind:"info", ...}, {type:"mc", ...}, {type:"match", ...}, etc.
Progress is stored in user.progress.fkPlay[lang][lessonId].
This system NEVER touches user.progress.lessons or user.progress.foundation.
*/

